2509→  private reorderOrMoveConversations(
2510→    conversationIds: string[],
2511→    sourceParentId: string,
2512→    targetParentId: string,
2513→    insertIndex: number,
2514→  ): void {
2515→    if (!this.data.folderContents[targetParentId]) {
2516→      this.data.folderContents[targetParentId] = [];
2517→    }
2518→
2519→    const movingConvs: ConversationReference[] = [];
2520→
2521→    // Deduplicate conversation IDs to prevent duplicates from cross-folder selection
2522→    const uniqueIds = [...new Set(conversationIds)];
2523→
2524→    // Collect conversation references
2525→    for (const convId of uniqueIds) {
2526→      const sourceList = this.data.folderContents[sourceParentId];
2527→      if (!sourceList) continue;
2528→      const conv = sourceList.find((c) => c.conversationId === convId);
2529→      if (conv) movingConvs.push(conv);
2530→    }
2531→
2532→    if (movingConvs.length === 0) return;
2533→
2534→    // When reordering within the same folder, insertIndex is based on the original
2535→    // sorted list (which includes the dragged items). After removal, indices shift.
2536→    // Adjust by subtracting the count of dragged items that were before insertIndex.
2537→    if (sourceParentId === targetParentId) {
2538→      const isStarredGroup = movingConvs[0].starred ?? false;
2539→      const originalSorted = this.sortConversations(
2540→        (this.data.folderContents[targetParentId] ?? []).filter(
2541→          (c) => !!c.starred === isStarredGroup,
2542→        ),
2543→      );
2544→      let adjustment = 0;
2545→      for (const convId of conversationIds) {
2546→        const origIdx = originalSorted.findIndex((c) => c.conversationId === convId);
2547→        if (origIdx >= 0 && origIdx < insertIndex) {
2548→          adjustment++;
2549→        }
2550→      }
2551→      insertIndex -= adjustment;
2552→    }
2553→
2554→    // Remove from source
2555→    if (this.data.folderContents[sourceParentId]) {
2556→      const removeSet = new Set(conversationIds);
2557→      this.data.folderContents[sourceParentId] = this.data.folderContents[sourceParentId].filter(
2558→        (c) => !removeSet.has(c.conversationId),
2559→      );
2560→      // Reassign sortIndex in source if it changed
2561→      if (sourceParentId !== targetParentId) {
2562→        const sourceConvs = this.sortConversations(this.data.folderContents[sourceParentId]);
2563→        sourceConvs.forEach((c, i) => {
2564→          c.sortIndex = i;
2565→        });
2566→      }
2567→    }
2568→
2569→    // Get target starred group info for proper insertion
2570→    const isStarred = movingConvs[0].starred ?? false;
2571→    const targetList = this.data.folderContents[targetParentId].filter(
2572→      (c) => !conversationIds.includes(c.conversationId),
2573→    );
2574→    this.data.folderContents[targetParentId] = targetList;
2575→
2576→    // Get sorted siblings in the same starred group (dragged items already excluded)
2577→    const sameGroupSiblings = this.sortConversations(
2578→      targetList.filter((c) => !!c.starred === isStarred),
2579→    );
2580→    const otherGroup = targetList.filter((c) => !!c.starred !== isStarred);
2581→
2582→    // Clamp insertIndex to valid range after removal
2583→    const clampedIndex = Math.min(insertIndex, sameGroupSiblings.length);
2584→
2585→    // Insert at position
2586→    sameGroupSiblings.splice(clampedIndex, 0, ...movingConvs);
2587→
2588→    // Reassign sortIndex
2589→    sameGroupSiblings.forEach((c, i) => {
2590→      c.sortIndex = i;
2591→    });
2592→    otherGroup.forEach((c, i) => {
2593→      if (c.sortIndex == null) c.sortIndex = i;
2594→    });
2595→
2596→    // Recombine
2597→    this.data.folderContents[targetParentId] = [...sameGroupSiblings, ...otherGroup];
2598→
2599→    this.saveData();
2600→    this.refresh();
2601→  }
